async (params, browser) => {
  // Search Letterboxd films
  await browser.open(`https://letterboxd.com/search/${params.query}/`)

  // Wait for results
  await browser.waitForSelector('ul.results, li.search-result', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('li.search-result').forEach((el,i) => { if(i>=10) return; const titleEl = el.querySelector('h2 a, span.film-title-wrapper a, a'); const yearEl = el.querySelector('small.metadata, span.metadata'); const dirEl = el.querySelector('p.film-metadata a, a.text-sluglist'); const link = titleEl?titleEl.getAttribute('href'):''; results.push({ title: titleEl?titleEl.textContent.trim():'', year: yearEl?yearEl.textContent.trim():'', director: dirEl?dirEl.textContent.trim():'', url: link?'https://letterboxd.com'+link:'' }); }); return { query: '' + params.query + '', results }`)

  return search_results
}
